ALTER TABLE `suppliers` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;
ALTER TABLE `ingredients` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;
ALTER TABLE `semi_finished_recipes` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;
ALTER TABLE `final_recipes` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;
ALTER TABLE `food_matrix` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;
ALTER TABLE `weekly_productions` ADD COLUMN IF NOT EXISTS `storeId` varchar(36) NOT NULL DEFAULT 'default-store-001' AFTER `id`;

-- Creare indici per performance
CREATE INDEX IF NOT EXISTS `idx_suppliers_storeId` ON `suppliers`(`storeId`);
