CREATE INDEX IF NOT EXISTS `idx_food_matrix_storeId` ON `food_matrix`(`storeId`);
CREATE INDEX IF NOT EXISTS `idx_weekly_productions_storeId` ON `weekly_productions`(`storeId`);

